// Project.js - Redesigned
import React, { useState, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import { motion } from 'framer-motion';
import Navbar from '../components/Navbar';

const API = '';

export default function Project() {
  const [searchParams, setSearchParams] = useSearchParams();
  const [projects, setProjects] = useState([]);
  const [kategoriList, setKategoriList] = useState([]);
  const filterKategori = parseInt(searchParams.get('kategori')) || 0;

  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  useEffect(() => {
    const url = filterKategori > 0
      ? `${API}/api/projects/public?kategori=${filterKategori}`
      : `${API}/api/projects/public`;
    fetch(url).then(r => r.json()).then(setProjects).catch(console.error);
  }, [filterKategori]);

  useEffect(() => {
    fetch(`${API}/api/kategori`).then(r => r.json()).then(setKategoriList).catch(console.error);
  }, []);

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.08, delayChildren: 0.2 }
    }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 30 },
    visible: { opacity: 1, y: 0, transition: { duration: 0.5, ease: [0.34, 1.56, 0.64, 1] } }
  };

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@400;500;600;700;800;900&family=Inter:wght@300;400;500;600;700&family=IBM+Plex+Mono:wght@400;500;600&display=swap');

        * { margin: 0; padding: 0; box-sizing: border-box; }

        body {
          background: #090909;
          color: #F5F5F5;
          font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
          min-height: 100vh;
          overflow-x: hidden;
          position: relative;
        }

        body::before {
          content: '';
          position: fixed;
          inset: 0;
          z-index: 0;
          pointer-events: none;
          background-image: 
            radial-gradient(circle at 20% 30%, rgba(255,62,165,0.03) 0%, transparent 50%),
            radial-gradient(circle at 80% 70%, rgba(216,167,177,0.03) 0%, transparent 50%),
            radial-gradient(circle at 50% 50%, rgba(255,124,199,0.02) 0%, transparent 70%);
          opacity: 0.5;
        }

        .leopard-bg {
          position: fixed;
          inset: 0;
          z-index: 0;
          pointer-events: none;
          opacity: 0.03;
          background-image: 
            radial-gradient(ellipse 3px 2px at 10% 20%, #fff 0%, transparent 100%),
            radial-gradient(ellipse 4px 3px at 30% 40%, #fff 0%, transparent 100%),
            radial-gradient(ellipse 2px 3px at 50% 10%, #fff 0%, transparent 100%),
            radial-gradient(ellipse 3px 2px at 70% 60%, #fff 0%, transparent 100%),
